The `debounce` function prevents a function from being called multiple times in quick succession, only calling it after a certain delay has passed since the last call.
```javascript
function debounce(callback, delay) {
  let timeout;
  return function(...args) {
    clearTimeout(timeout);
    timeout = setTimeout(() => callback(...args), delay);
  };
}

// Example usage:
const debouncedLog = debounce(console.log, 500);
debouncedLog('Hello'); // Not logged immediately
setTimeout(() => debouncedLog('World'), 200); // Not logged
setTimeout(() => debouncedLog('Debounced'), 700); // Logged after 500ms
```
